package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.BackupCodeEntity;
import com.example.mfa.repo.UserRepository;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.HashSet;
import java.util.List;
import java.util.Optional;
import java.util.Set;
import java.util.UUID;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class MfaService {
    private static final int BACKUP_CODE_COUNT = 10;
    private static final int BACKUP_CODE_BYTES = 9;

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public MfaService(UserRepository userRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(String username, String totpSecret) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        user.setTotpSecret(totpSecret);
        user.setMfaEnabledAt(Instant.now());

        List<String> plainCodes = new ArrayList<>();
        Set<BackupCodeEntity> codes = new HashSet<>();

        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String rawCode = generateBackupCode();
            String hash = passwordEncoder.encode(rawCode);
            BackupCodeEntity entity = new BackupCodeEntity();
            entity.setCodeHash(hash);
            entity.setUsed(false);
            entity.setCreatedAt(Instant.now());
            codes.add(entity);
            plainCodes.add(rawCode);
        }

        user.setBackupCodes(codes);
        userRepository.save(user);
        return plainCodes;
    }

    @Transactional
    public boolean authenticateWithBackupCode(String username, String backupCode) {
        Optional<AppUser> userOpt = userRepository.findByUsername(username);
        if (userOpt.isEmpty()) {
            return false;
        }

        AppUser user = userOpt.get();
        if (!user.isMfaEnabled() || user.getBackupCodes() == null || user.getBackupCodes().isEmpty()) {
            return false;
        }

        for (BackupCodeEntity code : user.getBackupCodes()) {
            if (!code.isUsed() && passwordEncoder.matches(backupCode, code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                userRepository.save(user);
                return true;
            }
        }
        return false;
    }

    @Transactional
    public List<String> regenerateBackupCodes(String username) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA is not enabled");
        }
        List<String> codes = new ArrayList<>();
        Set<BackupCodeEntity> entities = new HashSet<>();
        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String rawCode = generateBackupCode();
            BackupCodeEntity entity = new BackupCodeEntity();
            entity.setCodeHash(passwordEncoder.encode(rawCode));
            entity.setUsed(false);
            entity.setCreatedAt(Instant.now());
            entities.add(entity);
            codes.add(rawCode);
        }
        user.setBackupCodes(entities);
        userRepository.save(user);
        return codes;
    }

    private String generateBackupCode() {
        byte[] bytes = new byte[BACKUP_CODE_BYTES];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase();
    }
}

package com.example.mfa.web;

import com.example.mfa.service.MfaService;
import java.util.List;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable")
    public ResponseEntity<EnableMfaResponse> enableMfa(@RequestBody EnableMfaRequest request) {
        List<String> backupCodes = mfaService.enableMfaAndGenerateBackupCodes(request.getUsername(), request.getTotpSecret());
        return ResponseEntity.ok(new EnableMfaResponse(true, backupCodes));
    }

    @PostMapping("/backup-code/login")
    public ResponseEntity<BackupLoginResponse> loginWithBackupCode(@RequestBody BackupLoginRequest request) {
        boolean success = mfaService.authenticateWithBackupCode(request.getUsername(), request.getBackupCode());
        return ResponseEntity.ok(new BackupLoginResponse(success));
    }

    @PostMapping("/backup-code/regenerate")
    public ResponseEntity<EnableMfaResponse> regenerateBackupCodes(@RequestBody EnableMfaRequest request) {
        List<String> backupCodes = mfaService.regenerateBackupCodes(request.getUsername());
        return ResponseEntity.ok(new EnableMfaResponse(true, backupCodes));
    }
}

